import{_ as n,o as t,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"F05: 應收帳款品質與收款天數","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F05_應收帳款品質與收款天數_財務分析專家.md","filePath":"32Ｑ題本＿重要/財務組/F05_應收帳款品質與收款天數_財務分析專家.md"}'),a={name:"32Ｑ題本＿重要/財務組/F05_應收帳款品質與收款天數_財務分析專家.md"};function e(r,o,s,c,g,d){return t(),i("div",null,[...o[0]||(o[0]=[l('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f05-應收帳款品質與收款天數" tabindex="-1">F05: 應收帳款品質與收款天數 <a class="header-anchor" href="#f05-應收帳款品質與收款天數" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F05</li><li><strong>題目：</strong> 應收帳款 (AR) 的規模與週轉天數 (DSO) 變動為何？是否存在客戶拖欠或虛增營收風險？</li><li><strong>推薦專家：</strong> 財務分析師 (<code>finance-financial-analyst</code>)</li><li><strong>推薦理由：</strong> 專精於「營運資金效率 (Working Capital Efficiency)」與「信用風險評估」。具備從帳齡分析中識別「呆帳風險」與「營收含金量」的能力。分析師的職責在於確保利潤不僅是帳面數字，而是能如期回收的現金。</li><li><strong>意圖：</strong> 執行「資產品質與營收真偽審計」。透過測算應收帳款週轉天數與對比營收成長率，識別是否存在「塞貨」或「放寬信用額度衝業績」的激進行為，評估公司的資金回收安全性。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockBalanceSheet</code> 提取 <code>AccountsReceivable</code> (應收帳款)；調用 <code>TaiwanStockFinancialStatements</code> 提取 <code>Revenue</code>。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱 <code>財務報告附註 -&gt; 應收帳款帳齡分析</code> 與 <code>預期信用損失</code>。獲取逾期款項之真實比例。</li><li><strong>【外部事實檢索：客戶財務狀況】</strong>：若 AR 集中度高（前三大客戶佔比大），則需檢索關鍵客戶之近期信用新聞。</li></ol></li><li><strong>邏輯：</strong> 執行「應收帳款比/營收比背離測試」——若 AR 成長速度顯著高於營收成長，且 DSO 天數拉長 &gt; 20%，必須判定為「獲利品質虛胖」；執行「帳齡攤還壓力測試」。</li><li><strong>來源：</strong> <code>FinMind (資產/營收)</code>, <code>年度報告 (帳齡附註)</code>, <code>MOPS 分部資訊 (客戶集中度)</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>跑工具</strong>：<code>python3 財務分析工具.py receivable_check [股號]</code> → 取得 DSO、AR/營收比</li><li><strong>判讀 DSO</strong>：DSO &lt;60 天 = 優；60-90 = 正常；&gt;90 = 偏高；&gt;120 = 警戒</li><li><strong>對比</strong>：若 DSO 大幅上升但營收成長，需計算 AR 成長率 / 營收成長率，若 &gt;1.5 倍 = 營收品質稀釋</li><li><strong>年報補充</strong>：用 <code>pdf</code> 工具提取「應收帳款帳齡表」確認有無逾期款項</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【收款天數實測】</strong>：智慧體<strong>必須</strong>計算出具體的「應收帳款週轉天數 (DSO)」。嚴禁模糊描述「收款尚屬正常」。</li><li><strong>【背離趨勢診斷】</strong>：比對近三季「應收帳款成長率」與「營收成長率」。若兩者發生死亡交叉（AR 升、營收降），必須發出「放帳衝業績」或「客戶支付能力衰退」之警訊。</li><li><strong>【壞帳準備審查】</strong>：核對年報中「呆帳準備金」提列是否適足。若 DSO 天數拉長但提列比例反而下降，判定為「調節損益之激進會計手段」。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述約束】</strong>：絕對禁用「收款良好」、「客戶穩定」。必須量化為具體的「DSO 天數」與「逾期款項佔比 %」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f05-專家答詢】財務分析師-finance-financial-analyst" tabindex="-1">【F05 專家答詢】財務分析師 (finance-financial-analyst) <a class="header-anchor" href="#【f05-專家答詢】財務分析師-finance-financial-analyst" aria-label="Permalink to &quot;【F05 專家答詢】財務分析師 (finance-financial-analyst)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「收款效率+風險級別」結構（例：DSO 為 X 天，較去年同期拉長 Y 天，[收款效率] 出現停滯，應注意大型客戶 A 之 [信用風險]，獲利品質轉向 [保守]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：DSO 天數極短且持續下降，顯示對下游具備強大議價力與優質的客戶回款速度。</li><li><strong>A (良)</strong>：DSO 與營收成長同步，帳齡結構健康，無大額逾期款項。</li><li><strong>B (持平)</strong>：DSO 異常拉長且 AR 佔營收比重過高，顯示公司可能為了衝營收而過度放帳，資金鏈存有隱憂。</li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐，嚴禁脫離數據空泛推論。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確列出 FinMind <code>analysis</code> 收款天數指標與年報帳齡表頁碼。</li></ul>',11)])])}const h=n(a,[["render",e]]);export{f as __pageData,h as default};
